PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE bookings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    bookingId TEXT,
    name TEXT,
    dob TEXT,
    district TEXT,
    email TEXT,
    phone TEXT,
    proof TEXT,
    proof_file TEXT,
    photo TEXT,
    message TEXT,
    created_at TEXT
);
CREATE TABLE contacts (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        email TEXT NOT NULL,
        phone TEXT,
        message TEXT NOT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );
CREATE TABLE tournament_entries (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        team_name TEXT NOT NULL,
        captain_name TEXT NOT NULL,
        captain_phone TEXT NOT NULL,
        players TEXT NOT NULL,
        tournament_type TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );
CREATE TABLE users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username VARCHAR(50) UNIQUE NOT NULL,
            email VARCHAR(100) UNIQUE NOT NULL,
            password_hash VARCHAR(255) NOT NULL,
            role VARCHAR(20) DEFAULT 'user',
            is_active BOOLEAN DEFAULT 1,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            last_login DATETIME,
            login_attempts INTEGER DEFAULT 0,
            locked_until DATETIME
        );
CREATE TABLE registrations (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            reg_id VARCHAR(10) NOT NULL,
            name VARCHAR(100) NOT NULL,
            mobile VARCHAR(15) NOT NULL,
            email VARCHAR(100),
            city VARCHAR(50) NOT NULL,
            state VARCHAR(50) NOT NULL,
            date_of_birth DATE,
            document_type VARCHAR(20),
            document_number VARCHAR(20),
            address TEXT,
            parent_name VARCHAR(100),
            emergency_contact VARCHAR(15),
            blood_group VARCHAR(5),
            joined DATE NOT NULL,
            previous_tournaments TEXT,
            photo VARCHAR(255),
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        , document_number_normalized VARCHAR(64) DEFAULT NULL, download_token VARCHAR(64) DEFAULT NULL, status VARCHAR(20) DEFAULT 'active', district TEXT DEFAULT '');
CREATE TABLE search_logs (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_type VARCHAR(20) NOT NULL,
        search_term VARCHAR(100) NOT NULL,
        search_type VARCHAR(20) NOT NULL,
        results_count INTEGER DEFAULT 0,
        ip_address VARCHAR(45) NOT NULL,
        user_agent TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );
CREATE TABLE download_logs (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        registration_id INTEGER NOT NULL,
        user_type VARCHAR(20) NOT NULL,
        download_type VARCHAR(20) NOT NULL,
        ip_address VARCHAR(45) NOT NULL,
        user_agent TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY (registration_id) REFERENCES registrations(id)
    );
CREATE TABLE event_registrations (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            registration_id INTEGER NOT NULL,
            event_name TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (registration_id) REFERENCES registrations(id)
        );
CREATE TABLE admin_logs (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                admin_id VARCHAR(50),
                action VARCHAR(50) NOT NULL,
                details TEXT,
                ip_address VARCHAR(45),
                user_agent TEXT,
                created_at DATETIME DEFAULT CURRENT_TIMESTAMP
            );
CREATE TABLE tournaments (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    tournament_id TEXT UNIQUE,
    name TEXT NOT NULL,
    start_date TEXT,
    end_date TEXT,
    venue TEXT,
    city TEXT,
    state TEXT DEFAULT 'Maharashtra',
    participants INTEGER DEFAULT 0,
    status TEXT DEFAULT 'upcoming',
    winner TEXT DEFAULT '',
    runner_up TEXT DEFAULT '',
    organizer TEXT DEFAULT '',
    contact_person TEXT DEFAULT '',
    contact_mobile TEXT DEFAULT '',
    prize_money TEXT DEFAULT '',
    description TEXT DEFAULT '',
    image_path TEXT DEFAULT '',
    featured INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE gallery_images (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    filename TEXT NOT NULL,
    original_name TEXT,
    category TEXT DEFAULT 'general',
    tournament_id INTEGER DEFAULT NULL,
    caption TEXT DEFAULT '',
    uploaded_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE admin_users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    last_login DATETIME
);
CREATE TABLE contact_messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL, email TEXT NOT NULL, phone TEXT DEFAULT '',
    message TEXT NOT NULL, is_read INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE coach_users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    district TEXT NOT NULL,
    mobile TEXT DEFAULT '',
    name TEXT DEFAULT '',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE coach_reports (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    coach_id INTEGER NOT NULL,
    district TEXT NOT NULL,
    event_name TEXT,
    report_text TEXT,
    selected_registrations TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (coach_id) REFERENCES coach_users(id)
);
CREATE TABLE districts (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT UNIQUE NOT NULL);
CREATE TABLE media_images (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            filename TEXT NOT NULL,
            filepath TEXT NOT NULL,
            section TEXT DEFAULT 'gallery', -- logical section e.g. hero, gallery, banner
            alt_text TEXT DEFAULT '',
            enabled INTEGER DEFAULT 1,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        );
CREATE TABLE hero_banners (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT DEFAULT '',
            subtitle TEXT DEFAULT '',
            image_id INTEGER DEFAULT NULL,
            image_path TEXT DEFAULT '',
            link TEXT DEFAULT '',
            enabled INTEGER DEFAULT 1,
            position INTEGER DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (image_id) REFERENCES media_images(id)
        );
CREATE TABLE coach_applications (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        mobile TEXT NOT NULL,
        email TEXT DEFAULT '',
        district TEXT NOT NULL,
        photo_path TEXT DEFAULT '',
        status TEXT DEFAULT 'pending',
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );
CREATE UNIQUE INDEX idx_document_number ON registrations(document_number);
CREATE INDEX idx_mobile_search ON registrations(mobile);
CREATE INDEX idx_name_search ON registrations(name);
CREATE INDEX idx_reg_id_search ON registrations(reg_id);
CREATE INDEX idx_registrations_status ON registrations(status);
CREATE INDEX idx_registrations_created ON registrations(created_at);
CREATE INDEX idx_admin_logs_created ON admin_logs(created_at);
CREATE INDEX idx_event_registrations_reg_id ON event_registrations(registration_id);
COMMIT;
